@Test public void nullValueAttributesReturnEmptyString() {
    Attribute attr = new Attribute("test", null);
    assertEquals("", attr.getValue());
    assertNotNull(attr.getValue());
}

@Test public void explicitEmptyStringValuePreserved() {
    Attribute attr = new Attribute("test", "");
    assertEquals("", attr.getValue());
    assertNotNull(attr.getValue());
}

@Test public void nonEmptyValuePreserved() {
    Attribute attr = new Attribute("test", "value");
    assertEquals("value", attr.getValue());
}
